function bgImg(category,seed){
  let pool;
  if(category==="school")pool=BG_IMG_SCHOOL;
  else if(category==="city")pool=BG_IMG_CITY;
  else if(category==="수학")pool=BG_IMG_MATH;
  else if(category==="과학")pool=BG_IMG_SCIENCE;
  else if(category==="국어")pool=BG_IMG_KOREAN;
  else if(category==="영어")pool=BG_IMG_ENGLISH;
  else if(category==="사회")pool=BG_IMG_SOCIAL;
  else pool=BG_IMG_BOOKS;
  const id=pool[((seed>>>0)+pool.length)%pool.length];
  return "https://images.unsplash.com/photo-"+id+"?w=1400&q=70&auto=format&fit=crop";
}

function hexToRgba(hex,alpha){
  hex=hex.replace("#","");
  if(hex.length===3)hex=hex.split("").map(function(c){return c+c}).join("");
  const r=parseInt(hex.substr(0,2),16);
  const g=parseInt(hex.substr(2,2),16);
  const b=parseInt(hex.substr(4,2),16);
  return "rgba("+r+","+g+","+b+","+alpha+")";
}


function buildEduData() {
  const data = {};
  for (const [rs, ri] of Object.entries(locations)) {
    data[rs] = {};
    for (const [cs, ci] of Object.entries(ri.cities)) {
      const kn = ci.name;
      const classList = [];
      for (const g of grades) for (const s of subjects) {
        const raw = descriptions[g][s];
        classList.push({ grade:g, subject:s, title:kn+" "+g+" "+s+"과외", desc:raw.replace(/{region}/g,kn) });
      }
      data[rs][cs] = { region_display:ri.region_name+" "+kn, name:kn, schools:ci.schools||[], dongs:ci.dongs||[], classes:classList };
    }
  }
  return data;
}
const eduData = buildEduData();

// index.html base64
const INDEX_B64 = "";
function getIndex() {
  const bytes = Uint8Array.from(atob(INDEX_B64), c => c.charCodeAt(0));
  let html = new TextDecoder("utf-8").decode(bytes);
  // 메인 홈페이지에도 세부 페이지와 동일한 로고 이미지 적용
  html = html.replace(
    '<a href="/" class="nav-logo">🌟 <span',
    '<a href="/" class="nav-logo"><img src="data:image/jpeg;base64,' + BRAND_B64 + '" alt="은빛과외" style="width:36px;height:36px;object-fit:contain;"> <span'
  );
  return html;
}

